const base = 'http://prometheus:9090/api/v1/query';

async function query(expr) {
  const res = await fetch(`${base}?query=${encodeURIComponent(expr)}`);
  const data = await res.json();
  const first = data?.data?.result?.[0]?.value?.[1];
  const n = Number(first);
  return Number.isFinite(n) ? n : null;
}

const cpu = await query('100 - (avg(irate(node_cpu_seconds_total{mode="idle"}[5m])) * 100)');
const mem = await query('(1 - (node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes)) * 100');
const swap = await query('(1 - (node_memory_SwapFree_bytes / node_memory_SwapTotal_bytes)) * 100');
const diskFree = await query('(node_filesystem_avail_bytes{mountpoint="/",fstype!~"tmpfs|overlay"} / node_filesystem_size_bytes{mountpoint="/",fstype!~"tmpfs|overlay"}) * 100');
const downCount = await query('count(up == 0)');
const probeFail = await query('count(probe_success == 0)');

const issues = [];
if ((swap ?? 0) >= 70) issues.push(`Swap alta (${swap.toFixed(1)}%)`);
if ((diskFree ?? 100) <= 20) issues.push(`Disco libre bajo en / (${diskFree.toFixed(1)}%)`);
if ((cpu ?? 0) >= 90) issues.push(`CPU alta (${cpu.toFixed(1)}%)`);
if ((mem ?? 0) >= 90) issues.push(`RAM alta (${mem.toFixed(1)}%)`);
if ((downCount ?? 0) > 0) issues.push(`Servicios down: ${Number(downCount).toFixed(0)}`);
if ((probeFail ?? 0) > 0) issues.push(`HTTP probes KO: ${Number(probeFail).toFixed(0)}`);

const currentState = issues.length ? 'ALERT' : 'OK';
const store = $getWorkflowStaticData('global');
const lastState = store.lastState || 'OK';
const lastSent = Number(store.lastSent || 0);
const now = Date.now();

let shouldSend = false;
if (currentState === 'ALERT' && lastState !== 'ALERT') shouldSend = true;
if (currentState === 'ALERT' && lastState === 'ALERT' && now - lastSent > 6 * 60 * 60 * 1000) shouldSend = true;
if (currentState === 'OK' && lastState === 'ALERT') shouldSend = true;

store.lastState = currentState;
if (shouldSend) store.lastSent = now;
if (!shouldSend) return [];

const header = currentState === 'ALERT' ? 'GUARD ALERTA' : 'GUARD RESUELTO';
const body = currentState === 'ALERT'
  ? issues.map((i) => `- ${i}`).join('\n')
  : 'Condiciones de riesgo normalizadas.';

const msg = [
  `${header}`,
  `Hora: ${new Date().toISOString()}`,
  body,
  `CPU ${cpu?.toFixed(1) ?? 'n/a'}% | RAM ${mem?.toFixed(1) ?? 'n/a'}% | Swap ${swap?.toFixed(1) ?? 'n/a'}% | Disk libre ${diskFree?.toFixed(1) ?? 'n/a'}%`
].join('\n');

return [{ json: { message: msg } }];
